package main

import (
	"database/sql"
	"fmt"
	"strings"
)

// Product holds product data
type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Allowed columns for ORDER BY
	allowedColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}

	// Normalize input
	col := strings.ToLower(orderBy)
	if !allowedColumns[col] {
		return nil, fmt.Errorf("invalid orderBy column: %s", orderBy)
	}

	direction := strings.ToUpper(sortDir)
	if direction != "ASC" && direction != "DESC" {
		return nil, fmt.Errorf("invalid sortDir: must be ASC or DESC")
	}

	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", col, direction)

	rows, err := db.Query(query)
	if err != nil {
		return nil, fmt.Errorf("failed to execute query: %w", err)
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name, &p.Price); err != nil {
			return nil, fmt.Errorf("failed to scan row: %w", err)
		}
		products = append(products, p)
	}

	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("row iteration error: %w", err)
	}

	return products, nil
}

func main() {
	fmt.Println("ListProducts function is ready")
}

